create table public.workout_sessions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, import_id uuid not null, import_file_id uuid not null, dedupe_key text not null, source_record_hash text not null, workout_type text not null, started_at timestamptz not null, ended_at timestamptz not null, duration_seconds integer not null, distance_metres numeric, energy_kilocalories numeric, parser_version text not null, constraint workout_sessions_owner_dedupe unique(user_id,dedupe_key), constraint workout_sessions_owner_fk foreign key(import_id,user_id) references public.import_runs(id,user_id) on delete cascade, constraint workout_sessions_file_fk foreign key(import_file_id,import_id,user_id) references public.import_files(id,import_id,user_id) on delete cascade, constraint workout_sessions_time check(ended_at>started_at and duration_seconds>0));
alter table public.workout_sessions enable row level security;
grant select on public.workout_sessions to authenticated;
create policy "Workout sessions are readable by owner" on public.workout_sessions for select to authenticated using ((select auth.uid())=user_id);
